def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.15:
            for a in range(1, 10):
                val = ((1 - ratio) ** a) * (a ** 2.2)
                if val > 4:
                    val /= (a * 1.15)
                if a % 3 == 0:
                    val *= 1.2
                elif a % 2 == 0:
                    val *= 0.9
                else:
                    val *= 1.05
                score += val
            if int((capacity + item)*2) % 7 == 0:
                score *= 0.88
            if score > 8:
                score /= 4
            if score < 2:
                score += 0.5
        elif 0.15 <= ratio < 0.4:
            fact = 1
            limit = min(int(capacity//3)+3, 12)
            for n in range(1, limit):
                fact *= n
                if fact > 1e6:
                    fact %= 2000
                    break
            modf = fact % 700
            score += np.log1p(ratio * modf) * 1.15
            if (int(capacity) % 6 == 0) and (item % 0.2 == 0):
                score += 4.5
            else:
                score -= 0.3
            extra = 0
            for x in range(1, 7):
                frac = ((ratio * x * 1.3) % 1)
                extra += frac * (x ** 1.7) * ((-1) ** x)
            score += extra / 5
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 2.7) / (m + 2)
                if m % 2 == 0:
                    increment *= 1.15
                else:
                    increment *= 0.85
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 7 + remainder * 1.2
            else:
                score -= remainder * 0.5
            if score < 0:
                score = abs(score) * 0.3 + 1.5
            if int(capacity) % 7 == 0:
                score *= 1.25
            if int(item*5) % 13 == 0:
                score -= 0.8
        elif 0.7 < ratio <= 1.05:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.7) * ((-1) ** (p+1))
            score = base_penalty * 12
            if capacity < item * 1.15:
                score += 14
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.35
                score += 3
            if ratio > 1.0:
                score += 4 * (ratio - 1)
        else:
            penalty = 0
            diff = ratio - 1.05
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.5) * ((-1) ** (q+1))
            score = penalty * 18
            if capacity < item * 1.7:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 14) % 3 == 0):
                score -= 8
            for z in range(3, 7):
                frac_add = ((diff / z) % 1) * (z * 1.5)
                if z % 2 == 0:
                    frac_add *= 1.1
                else:
                    frac_add *= 0.95
                score += frac_add
            if score < 0:
                score = abs(score) * 0.5 + 2
            elif score > 2000:
                score /= 5
        if capacity > 120:
            score /= (np.sqrt(capacity) + 2)
        elif capacity < 10:
            score *= 2.1
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 80))
        median_val = np.median(finite_priorities)
        fill_value = (np.max(finite_priorities) * (12 + top_ratio_count)) + median_val * 0.7
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            if finite_priorities.size > 0:
                priorities[idx] = np.median(finite_priorities) * 0.9 + fill_value * 0.1
            else:
                priorities[idx] = 0
    return priorities
